include <sys/types.h>
include <fcntl.h>
include <unistd.h>


define FILE "/tmp/myfile"
define UID 100


void test(char *str)
{
int fd;
fd = creat(FILE, 0644);
if(fd == -1)
return;

chown(FILE, UID, -1); /* BAD */
close(fd);

}


int main(int argc, char **argv)
{
char *userstr;
if(argc > 1) {
userstr = argv[1];
test(userstr);

}
return 0;

}
